define(['jquery','underscore','uiComponent','Magento_Customer/js/customer-data','Magento_Ui/js/modal/modal'],function($,_,Component,customerData,modal){'use strict';var options={type:'popup',responsive:true,innerScroll:false,title:'Wishlist',modalClass:'modal-popup',width:50,height:50,modalLeftMargin:45,buttons:[{text:$.mage.__('Close'),class:'custom-wishlist-response',click:function(){this.closeModal();}}]};return Component.extend({productIds:[],initialize:function(){this._super();this.initWishlistProduct();},initWishlistProduct:function(){this.wishlist=customerData.get('wishlist');this.wishlist.subscribe(function(value){this.productIds(value.wishlist_ids||[])},this);this.observe('productIds',[]);this.productIds(this.wishlist().wishlist_ids||[]);},beforeSendAjaxEvent:function(ajaxWishlist,event){},completeAjaxEvent:function(ajaxWishlist,event){},added:function(element){return _.isArray(this.productIds())&&this.productIds.indexOf($(element).data('product-id').toString())>-1;}});});